package com.seaquake6324.civitas.application;
import static org.junit.jupiter.api.Assertions.*;import com.seaquake6324.civitas.domain.population.*;import com.seaquake6324.civitas.infrastructure.persistence.PopulationSavedData;import java.util.*;import org.junit.jupiter.api.Test;
class AdoptOrphanServiceTest{@Test void movesExistingChildAtomicallyFromOriginToNpcGuardians(){PopulationSavedData data=new PopulationSavedData();UUID city=UUID.randomUUID(),residence=UUID.randomUUID();CitizenRecord child=citizen(UUID.randomUUID(),city,0),a=citizen(UUID.randomUUID(),city,432000),b=citizen(UUID.randomUUID(),city,432000);FamilyMemberRef ar=FamilyMemberRef.citizen(a.id()),br=FamilyMemberRef.citizen(b.id());Household origin=new Household(UUID.randomUUID(),city,Set.of(),Set.of(),Set.of(),Set.of(child.id()),residence,20,20,1);Household family=new Household(UUID.randomUUID(),city,Set.of(ar,br),Set.of(),Set.of(),Set.of(),residence,80,90,1);data.putCitizen(child.withHousehold(origin.id()));data.putCitizen(a.withHousehold(family.id()));data.putCitizen(b.withHousehold(family.id()));data.putHousehold(origin);data.putHousehold(family);UUID p1=UUID.randomUUID(),p2=UUID.randomUUID();data.putProfile(new PlayerCivitasProfile(p1,Gender.MALE,1));data.putProfile(new PlayerCivitasProfile(p2,Gender.FEMALE,1));data.putParentage(new ParentageRecord(child.id(),city,Set.of(FamilyMemberRef.player(p1),FamilyMemberRef.player(p2)),0,false,ParentageRecord.Source.BIRTH,1));OrphanRecord orphan=new OrphanRecord(child.id(),city,OrphanRecord.Reason.PARENTS_UNAVAILABLE,origin.id(),residence,10,1);data.putOrphan(orphan);CitizenRecord storedChild=data.citizen(child.id()).orElseThrow(),storedA=data.citizen(a.id()).orElseThrow(),storedB=data.citizen(b.id()).orElseThrow();Household adoptive=family.addChild(child.id(),Set.of(ar,br));var result=new AdoptOrphanService().adopt(data,new AdoptOrphanService.Request(child.id(),1,storedChild.revision(),adoptive,family.revision(),origin.revision(),Map.of(a.id(),storedA.revision(),b.id(),storedB.revision()),8));assertTrue(result.success());assertTrue(data.orphan(child.id()).isEmpty());assertEquals(family.id(),data.citizen(child.id()).orElseThrow().householdId());assertEquals(residence,data.citizen(child.id()).orElseThrow().residenceId());assertFalse(data.household(origin.id()).orElseThrow().children().contains(child.id()));assertEquals(Set.of(ar,br),data.household(family.id()).orElseThrow().guardians());}
 private static CitizenRecord citizen(UUID id,UUID city,long age){return new CitizenRecord(id,"Mira","North",CitizenRace.HUMAN,"human_0",Gender.FEMALE,age,0,city,null,null,null,"",100,CitizenNeeds.neutral(),Map.of(),Set.of(),75,0,CitizenRuntimeState.VIRTUAL,0,70,0,1);}}
